import React, { useEffect, useState } from "react";
import { useLocation, useSearchParams } from "react-router-dom";
import { productAPI } from "../api";
import ProductGrid from "../components/product/ProductGrid";
import Sidebar from "../components/common/Sidebar";

const ProductList = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();
  const q = searchParams.get("q") || "";
  const category = searchParams.get("category") || "";

  useEffect(() => {
    setLoading(true);
    let mounted = true;
    const params = { q, category, limit: 24 };
    productAPI.getProducts(params).then(res => {
      if (mounted) setProducts(res.data || []);
    }).catch(err => console.error(err)).finally(() => mounted && setLoading(false));
    return () => mounted = false;
  }, [q, category]);

  return (
    <div style={{ display: "flex", gap: 24, padding: "24px 10%" }}>
      <Sidebar />
      <div style={{ flex: 1 }}>
        <h2 style={{ marginBottom: 18 }}>Kết quả tìm kiếm {q ? `: "${q}"` : ""}</h2>
        {loading ? <div>Đang tải...</div> : <ProductGrid products={products} />}
      </div>
    </div>
  );
};

export default ProductList;
